export const INTERCITY_VEHICLE_TIERS = [
  { label: 'מונית רגילה', passengers: '1–4', minPax: 1, maxPax: 4, index: 0 },
  { label: 'מיניבוס', passengers: '5–6', minPax: 5, maxPax: 6, index: 1 },
  { label: 'מיניבוס גדול', passengers: '7–8', minPax: 7, maxPax: 8, index: 2 },
  { label: 'ואן / מיניבוס', passengers: '9–10', minPax: 9, maxPax: 10, index: 3 },
  { label: 'אוטובוס קטן', passengers: '11–14', minPax: 11, maxPax: 14, index: 4 },
  { label: 'אוטובוס', passengers: '15–19', minPax: 15, maxPax: 19, index: 5 },
] as const

export function getIntercityTierIndex(passengers: number): number {
  if (passengers <= 4) return 0
  if (passengers <= 6) return 1
  if (passengers <= 8) return 2
  if (passengers <= 10) return 3
  if (passengers <= 14) return 4
  return 5
}

export function getIntercityPrice(origin: string, destination: string, passengers = 1, isNight = false): number | null {
  const arr = INTERCITY_PRICES[origin]?.[destination] ?? INTERCITY_PRICES[destination]?.[origin] ?? null
  if (!arr) return null
  const tierIdx = getIntercityTierIndex(passengers)
  return arr[tierIdx * 2 + (isNight ? 1 : 0)]
}
